### Fulfillment Progress

```rust
//! Partial fulfillment tracking.

use std::sync::atomic::{AtomicU32, Ordering};
use std::collections::HashSet;
use std::sync::RwLock;

/// Tracks progress toward fulfilling an obligation.
pub struct FulfillmentProgress {
    /// Total symbols required.
    total: u32,
    /// Symbols fulfilled so far.
    fulfilled: AtomicU32,
    /// Individual symbol IDs fulfilled (optional, for debugging).
    fulfilled_ids: RwLock<Option<HashSet<SymbolId>>>,
}

/// A snapshot of fulfillment progress.
#[derive(Clone, Debug)]
pub struct FulfillmentSnapshot {
    /// Total symbols required.
    pub total: u32,
    /// Symbols fulfilled so far.
    pub fulfilled: u32,
    /// Percentage complete (0.0 to 1.0).
    pub percent: f64,
    /// Whether fulfillment is complete.
    pub complete: bool,
}

impl FulfillmentProgress {
    /// Creates new progress tracker.
    #[must_use]
    pub fn new(total: u32) -> Self {
        Self {
            total,
            fulfilled: AtomicU32::new(0),
            fulfilled_ids: RwLock::new(None),
        }
    }

    /// Creates progress with individual tracking enabled.
    #[must_use]
    pub fn with_tracking(total: u32) -> Self {
        Self {
            total,
            fulfilled: AtomicU32::new(0),
            fulfilled_ids: RwLock::new(Some(HashSet::new())),
        }
    }

    /// Increments the fulfilled count.
    pub fn increment(&self) {
        self.fulfilled.fetch_add(1, Ordering::SeqCst);
    }

    /// Increments by a specific amount.
    pub fn add(&self, count: u32) {
        self.fulfilled.fetch_add(count, Ordering::SeqCst);
    }

    /// Records a specific symbol as fulfilled.
    pub fn record(&self, symbol_id: SymbolId) {
        self.increment();

        if let Some(ref mut ids) = *self.fulfilled_ids.write().expect("lock poisoned") {
            ids.insert(symbol_id);
        }
    }

    /// Returns the total required.
    #[must_use]
    pub fn total(&self) -> u32 {
        self.total
    }

    /// Returns the current fulfilled count.
    #[must_use]
    pub fn fulfilled(&self) -> u32 {
        self.fulfilled.load(Ordering::SeqCst)
    }

    /// Returns true if fulfillment is complete.
    #[must_use]
    pub fn is_complete(&self) -> bool {
        self.fulfilled() >= self.total
    }

    /// Returns the percentage complete (0.0 to 1.0).
    #[must_use]
    pub fn percent(&self) -> f64 {
        if self.total == 0 {
            1.0
        } else {
            f64::from(self.fulfilled()) / f64::from(self.total)
        }
    }

    /// Returns a snapshot of the current progress.
    #[must_use]
    pub fn snapshot(&self) -> FulfillmentSnapshot {
        let fulfilled = self.fulfilled();
        FulfillmentSnapshot {
            total: self.total,
            fulfilled,
            percent: self.percent(),
            complete: fulfilled >= self.total,
        }
    }

    /// Returns the remaining count.
    #[must_use]
    pub fn remaining(&self) -> u32 {
        self.total.saturating_sub(self.fulfilled())
    }

    /// Checks if a specific symbol has been fulfilled (if tracking enabled).
    #[must_use]
    pub fn is_fulfilled(&self, symbol_id: &SymbolId) -> Option<bool> {
        self.fulfilled_ids
            .read()
            .expect("lock poisoned")
            .as_ref()
            .map(|ids| ids.contains(symbol_id))
    }
}

impl fmt::Debug for FulfillmentProgress {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        f.debug_struct("FulfillmentProgress")
            .field("fulfilled", &self.fulfilled())
            .field("total", &self.total)
            .field("complete", &self.is_complete())
            .finish()
    }
}
