### Obligation Registry

```rust
//! Registry for tracking active obligations.

use std::collections::HashMap;
use std::sync::RwLock;
use crate::types::{ObligationId, RegionId, TaskId};

/// Registry that tracks all active symbolic obligations.
pub struct SymbolicObligationRegistry {
    /// Obligations by ID.
    by_id: RwLock<HashMap<ObligationId, ObligationEntry>>,
    /// Obligations by object ID (for lookup during cancellation).
    by_object: RwLock<HashMap<ObjectId, Vec<ObligationId>>>,
    /// Obligations by holder task.
    by_holder: RwLock<HashMap<TaskId, Vec<ObligationId>>>,
    /// Obligations by region.
    by_region: RwLock<HashMap<RegionId, Vec<ObligationId>>>,
    /// Next obligation ID.
    next_id: AtomicU64,
    /// Leak detector.
    leak_detector: Option<LeakDetector>,
}

/// Entry in the obligation registry.
struct ObligationEntry {
    /// The obligation's weak reference (for leak detection).
    id: ObligationId,
    kind: SymbolicObligationKind,
    object_id: ObjectId,
    holder: TaskId,
    region: RegionId,
    created_at: Time,
    state: SymbolicObligationState,
}

impl SymbolicObligationRegistry {
    /// Creates a new registry.
    #[must_use]
    pub fn new() -> Self {
        Self {
            by_id: RwLock::new(HashMap::new()),
            by_object: RwLock::new(HashMap::new()),
            by_holder: RwLock::new(HashMap::new()),
            by_region: RwLock::new(HashMap::new()),
            next_id: AtomicU64::new(1),
            leak_detector: None,
        }
    }

    /// Enables leak detection with the given detector.
    #[must_use]
    pub fn with_leak_detector(mut self, detector: LeakDetector) -> Self {
        self.leak_detector = Some(detector);
        self
    }

    /// Creates a send-object obligation and registers it.
    pub fn create_send_object(
        &self,
        object_id: ObjectId,
        params: &ObjectParams,
        holder: TaskId,
        region: RegionId,
        now: Time,
    ) -> SymbolicObligation {
        let id = self.allocate_id();

        let obligation = SymbolicObligation::new_send_object(
            id, object_id, params, holder, region, now,
        );

        self.register(&obligation);

        obligation
    }

    /// Creates a send-symbol obligation and registers it.
    pub fn create_send_symbol(
        &self,
        symbol_id: SymbolId,
        holder: TaskId,
        region: RegionId,
        now: Time,
    ) -> SymbolicObligation {
        let id = self.allocate_id();

        let obligation = SymbolicObligation::new_send_symbol(
            id, symbol_id, holder, region, now,
        );

        self.register(&obligation);

        obligation
    }

    /// Creates an acknowledge obligation and registers it.
    pub fn create_acknowledge(
        &self,
        object_id: ObjectId,
        expected_count: u32,
        holder: TaskId,
        region: RegionId,
        now: Time,
    ) -> SymbolicObligation {
        let id = self.allocate_id();

        let obligation = SymbolicObligation::new_acknowledge(
            id, object_id, expected_count, holder, region, now,
        );

        self.register(&obligation);

        obligation
    }

    /// Creates a decode obligation and registers it.
    pub fn create_decode(
        &self,
        object_id: ObjectId,
        min_symbols: u32,
        holder: TaskId,
        region: RegionId,
        now: Time,
    ) -> SymbolicObligation {
        let id = self.allocate_id();

        let obligation = SymbolicObligation::new_decode(
            id, object_id, min_symbols, holder, region, now,
        );

        self.register(&obligation);

        obligation
    }

    /// Updates the state of an obligation.
    pub fn update_state(&self, id: ObligationId, state: SymbolicObligationState) {
        if let Some(entry) = self.by_id.write().expect("lock poisoned").get_mut(&id) {
            entry.state = state;
        }
    }

    /// Returns obligations for a region.
    #[must_use]
    pub fn obligations_for_region(&self, region: RegionId) -> Vec<ObligationId> {
        self.by_region
            .read()
            .expect("lock poisoned")
            .get(&region)
            .cloned()
            .unwrap_or_default()
    }

    /// Returns obligations for a task.
    #[must_use]
    pub fn obligations_for_task(&self, task: TaskId) -> Vec<ObligationId> {
        self.by_holder
            .read()
            .expect("lock poisoned")
            .get(&task)
            .cloned()
            .unwrap_or_default()
    }

    /// Returns obligations for an object.
    #[must_use]
    pub fn obligations_for_object(&self, object_id: ObjectId) -> Vec<ObligationId> {
        self.by_object
            .read()
            .expect("lock poisoned")
            .get(&object_id)
            .cloned()
            .unwrap_or_default()
    }

    /// Checks for pending obligations in a region (blocks region close).
    #[must_use]
    pub fn has_pending_in_region(&self, region: RegionId) -> bool {
        let by_region = self.by_region.read().expect("lock poisoned");
        let by_id = self.by_id.read().expect("lock poisoned");

        if let Some(ids) = by_region.get(&region) {
            for id in ids {
                if let Some(entry) = by_id.get(id) {
                    if !entry.state.is_terminal() {
                        return true;
                    }
                }
            }
        }

        false
    }

    /// Gets pending obligations in a region.
    #[must_use]
    pub fn pending_in_region(&self, region: RegionId) -> Vec<ObligationSummary> {
        let by_region = self.by_region.read().expect("lock poisoned");
        let by_id = self.by_id.read().expect("lock poisoned");

        let mut result = Vec::new();

        if let Some(ids) = by_region.get(&region) {
            for id in ids {
                if let Some(entry) = by_id.get(id) {
                    if !entry.state.is_terminal() {
                        result.push(ObligationSummary {
                            id: entry.id,
                            kind: entry.kind,
                            object_id: entry.object_id,
                            holder: entry.holder,
                            state: entry.state,
                            created_at: entry.created_at,
                        });
                    }
                }
            }
        }

        result
    }

    /// Runs leak detection on completed tasks.
    pub fn detect_leaks(&self, completed_task: TaskId) -> Vec<LeakedObligation> {
        let mut leaked = Vec::new();

        let by_holder = self.by_holder.read().expect("lock poisoned");
        let by_id = self.by_id.read().expect("lock poisoned");

        if let Some(ids) = by_holder.get(&completed_task) {
            for id in ids {
                if let Some(entry) = by_id.get(id) {
                    if !entry.state.is_terminal() {
                        leaked.push(LeakedObligation {
                            id: entry.id,
                            kind: entry.kind,
                            object_id: entry.object_id,
                            holder: completed_task,
                            created_at: entry.created_at,
                        });
                    }
                }
            }
        }

        // Notify leak detector
        if let Some(ref detector) = self.leak_detector {
            for leak in &leaked {
                detector.on_leak(leak);
            }
        }

        leaked
    }

    /// Returns registry statistics.
    #[must_use]
    pub fn stats(&self) -> RegistryStats {
        let by_id = self.by_id.read().expect("lock poisoned");

        let mut pending = 0;
        let mut committed = 0;
        let mut aborted = 0;
        let mut leaked = 0;

        for entry in by_id.values() {
            match entry.state {
                SymbolicObligationState::Reserved | SymbolicObligationState::InProgress => {
                    pending += 1;
                }
                SymbolicObligationState::Committed => committed += 1,
                SymbolicObligationState::Aborted => aborted += 1,
                SymbolicObligationState::Leaked => leaked += 1,
            }
        }

        RegistryStats {
            total: by_id.len(),
            pending,
            committed,
            aborted,
            leaked,
        }
    }

    fn allocate_id(&self) -> ObligationId {
        use crate::util::ArenaIndex;
        let raw = self.next_id.fetch_add(1, Ordering::SeqCst);
        ObligationId::from_arena(ArenaIndex::new(raw as u32, 0))
    }

    fn register(&self, obligation: &SymbolicObligation) {
        let entry = ObligationEntry {
            id: obligation.id(),
            kind: obligation.kind(),
            object_id: obligation.object_id(),
            holder: obligation.holder(),
            region: obligation.region(),
            created_at: obligation.created_at(),
            state: SymbolicObligationState::Reserved,
        };

        let id = entry.id;
        let object_id = entry.object_id;
        let holder = entry.holder;
        let region = entry.region;

        self.by_id.write().expect("lock poisoned").insert(id, entry);

        self.by_object
            .write()
            .expect("lock poisoned")
            .entry(object_id)
            .or_default()
            .push(id);

        self.by_holder
            .write()
            .expect("lock poisoned")
            .entry(holder)
            .or_default()
            .push(id);

        self.by_region
            .write()
            .expect("lock poisoned")
            .entry(region)
            .or_default()
            .push(id);
    }
}

impl Default for SymbolicObligationRegistry {
    fn default() -> Self {
        Self::new()
    }
}

