### Leak Detector

```rust
//! Leak detection for obligations.

use std::sync::Arc;

/// Trait for leak detection handlers.
pub trait LeakHandler: Send + Sync {
    /// Called when a leaked obligation is detected.
    fn on_leak(&self, leak: &LeakedObligation);
}

/// Leak detector configuration and handler.
pub struct LeakDetector {
    /// Handler for detected leaks.
    handler: Arc<dyn LeakHandler>,
    /// Whether to panic on leak in debug mode.
    panic_on_leak_debug: bool,
    /// Whether to log leaks.
    log_leaks: bool,
}

impl LeakDetector {
    /// Creates a new leak detector with the given handler.
    pub fn new(handler: impl LeakHandler + 'static) -> Self {
        Self {
            handler: Arc::new(handler),
            panic_on_leak_debug: true,
            log_leaks: true,
        }
    }

    /// Creates a leak detector that only logs.
    #[must_use]
    pub fn logging_only() -> Self {
        Self {
            handler: Arc::new(LoggingLeakHandler),
            panic_on_leak_debug: false,
            log_leaks: true,
        }
    }

    /// Sets whether to panic on leak in debug mode.
    #[must_use]
    pub fn with_panic_on_leak_debug(mut self, panic: bool) -> Self {
        self.panic_on_leak_debug = panic;
        self
    }

    /// Handles a detected leak.
    pub fn on_leak(&self, leak: &LeakedObligation) {
        if self.log_leaks {
            eprintln!(
                "LEAK DETECTED: {:?} obligation {} for object {} (holder: {:?})",
                leak.kind, leak.id, leak.object_id, leak.holder
            );
        }

        self.handler.on_leak(leak);

        #[cfg(debug_assertions)]
        if self.panic_on_leak_debug {
            panic!(
                "Obligation leak detected: {:?} for object {}",
                leak.kind, leak.object_id
            );
        }
    }
}

/// A leak handler that just logs.
struct LoggingLeakHandler;

impl LeakHandler for LoggingLeakHandler {
    fn on_leak(&self, leak: &LeakedObligation) {
        eprintln!("Obligation leaked: {:?}", leak);
    }
}

/// A leak handler that collects leaks for testing.
#[derive(Default)]
pub struct CollectingLeakHandler {
    leaks: std::sync::Mutex<Vec<LeakedObligation>>,
}

impl CollectingLeakHandler {
    /// Returns collected leaks.
    pub fn leaks(&self) -> Vec<LeakedObligation> {
        self.leaks.lock().expect("lock poisoned").clone()
    }

    /// Clears collected leaks.
    pub fn clear(&self) {
        self.leaks.lock().expect("lock poisoned").clear();
    }
}

impl LeakHandler for CollectingLeakHandler {
    fn on_leak(&self, leak: &LeakedObligation) {
        self.leaks.lock().expect("lock poisoned").push(leak.clone());
    }
}
