## Integration Patterns

### Sender Integration

```rust
use asupersync::obligation::symbol::*;

async fn send_with_obligation(
    sender: &mut RaptorQSender<T>,
    registry: &SymbolicObligationRegistry,
    object_id: ObjectId,
    params: &ObjectParams,
    symbols: Vec<Symbol>,
    holder: TaskId,
    region: RegionId,
) -> Result<()> {
    // Create obligation
    let obligation = registry.create_send_object(
        object_id,
        params,
        holder,
        region,
        Time::now(),
    );

    // Send symbols, tracking progress
    for symbol in symbols {
        match sender.send_symbol(symbol.clone()).await {
            Ok(()) => {
                obligation.fulfill_one(symbol.id());
            }
            Err(e) => {
                // On error, abort the obligation
                obligation.abort();
                return Err(e);
            }
        }
    }

    // Commit when all symbols sent
    obligation.commit();
    Ok(())
}
```

### Receiver Integration

```rust
async fn receive_with_obligation(
    receiver: &mut RaptorQReceiver<S>,
    registry: &SymbolicObligationRegistry,
    params: &ObjectParams,
    holder: TaskId,
    region: RegionId,
) -> Result<Vec<u8>> {
    // Create decode obligation
    let obligation = registry.create_decode(
        params.object_id,
        params.min_symbols_for_decode(),
        holder,
        region,
        Time::now(),
    );

    let mut symbols = Vec::new();

    while !obligation.progress().complete {
        match receiver.recv().await? {
            Some(symbol) => {
                obligation.fulfill_one(symbol.id());
                symbols.push(symbol);
            }
            None => {
                // Stream ended before complete
                obligation.abort();
                return Err(Error::new(ErrorKind::InsufficientSymbols));
            }
        }
    }

    // Decode
    let data = decode(&symbols)?;

    // Commit obligation
    obligation.commit();
    Ok(data)
}
```

### Region Close Integration

```rust
impl Region {
    async fn close(&mut self) -> Result<()> {
        // Check for pending obligations
        while self.registry.has_pending_in_region(self.id) {
            let pending = self.registry.pending_in_region(self.id);

            for summary in pending {
                // Give each pending obligation a chance to resolve
                self.poll_obligation(summary.id).await?;
            }

            // Check budget
            self.budget.decrement_poll()?;
        }

        Ok(())
    }
}
```

